ops.def:
$next() → Effect =
    if page < total_pages: page := page + 1 load_page(page) prev() → Effect =
    if page > 1: page := page - 1 load_page(page) goto(p: ℕ) → Effect =
    if 1 ≤ p ≤ total_pages: page := p load_page(p)$

$produce() → Effect = while state = flowing: chunk := producer.generate()
    if chunk = EndOfStream: state := ended consumer.close() else: buffer := enqueue(buffer, chunk)
    if buffer.size ≥ highWaterMark: state := paused producer.pause()$
